// File: tests/Value_WriteToStream_65_Test.cpp#include <gtest/gtest.h>#include <sstream>#include <string>#include <vector>#include <map>#include "JsonBox/Value.h"using JsonBox::Value;using JsonBox::Array;using JsonBox::Object;class ValueWriteToStreamTest_65 : public ::testing::Test {};// [Normal] String value produces output; escapeAll flag affects strings with escapable chars.TEST_F(ValueWriteToStreamTest_65, WritesStringAndRespectsEscapeFlag_65) {    Value v(std::string("a\"b\nc\t\\"));    std::ostringstream oss_min, oss_all;    ASSERT_NO_THROW(v.writeToStream(oss_min, /*indent=*/false, /*escapeAll=*/false));    ASSERT_NO_THROW(v.writeToStream(oss_all, /*indent=*/false, /*escapeAll=*/true));    const auto s_min = oss_min.str();    const auto s_all = oss_all.str();    // Should write something in both cases.    EXPECT_FALSE(s_min.empty());    EXPECT_FALSE(s_all.empty());    // For strings that contain escapable characters, the two modes should differ.    EXPECT_NE(s_min, s_all);    // Writing should append to existing stream content (not clear or replace it).    std::ostringstream oss_prefixed;    oss_prefixed << "prefix:";    v.writeToStream(oss_prefixed, false, false);    const auto prefixed = oss_prefixed.str();    ASSERT_GE(prefixed.size(), std::string("prefix:").size());    EXPECT_EQ(0u, prefixed.find("prefix:"));}// [Normal] Integer value: repeated writes with the same flags are consistent and deterministic.TEST_F(ValueWriteToStreamTest_65, WritesIntegerConsistently_65) {    Value v_int(123);    std::ostringstream oss1, oss2;    v_int.writeToStream(oss1, /*indent=*/false, /*escapeAll=*/false);    v_int.writeToStream(oss2, /*indent=*/false, /*escapeAll=*/false);    EXPECT_EQ(oss1.str(), oss2.str());    // Also check that writing again to the *same* stream appends (grows) rather than replaces.    const auto before_size = oss1.str().size();    v_int.writeToStream(oss1, /*indent=*/false, /*escapeAll=*/false);    EXPECT_GT(oss1.str().size(), before_size);}// [Boundary] Alphanumeric-only string should be identical with escapeAll on/off (no extra escaping needed).TEST_F(ValueWriteToStreamTest_65, EqualWhenNoEscapesNeeded_65) {    Value v_plain(std::string("AlphaNumericOnly123"));    std::ostringstream oss_min, oss_all;    v_plain.writeToStream(oss_min, /*indent=*/false, /*escapeAll=*/false);    v_plain.writeToStream(oss_all, /*indent=*/false, /*escapeAll=*/true);    EXPECT_EQ(oss_min.str(), oss_all.str());    EXPECT_FALSE(oss_min.str().empty());}// [Normal / Interaction] Indentation flag should have an observable effect for composite types.TEST_F(ValueWriteToStreamTest_65, IndentationAffectsCompositeTypes_65) {    Object obj;    obj["a"] = Value(1);    obj["b"] = Value(Array{ Value(2), Value(3) });    Value v_obj(obj);    std::ostringstream oss_no_indent, oss_indent;    v_obj.writeToStream(oss_no_indent, /*indent=*/false, /*escapeAll=*/false);    v_obj.writeToStream(oss_indent,    /*indent=*/true,  /*escapeAll=*/false);    const auto s_no = oss_no_indent.str();    const auto s_in = oss_indent.str();    // Content should be present and include keys (observable via substring).    EXPECT_NE(std::string::npos, s_no.find("a"));    EXPECT_NE(std::string::npos, s_no.find("b"));    EXPECT_NE(std::string::npos, s_in.find("a"));    EXPECT_NE(std::string::npos, s_in.find("b"));    // Indentation typically changes formatting; assert that there is a difference.    EXPECT_NE(s_no, s_in);}// [Exceptional/State] Writing should not modify the public, observable state of the value.TEST_F(ValueWriteToStreamTest_65, WriteDoesNotModifyValueState_65) {    const std::string original = "stay_the_same";    Value v_str(original);    // Snapshot observable state via public API.    const bool wasString = v_str.isString();    const std::string before = v_str.getString();    std::ostringstream oss;    ASSERT_NO_THROW(v_str.writeToStream(oss, /*indent=*/true, /*escapeAll=*/true));    // Publicly observable state should be unchanged after writing.    EXPECT_TRUE(wasString);    EXPECT_TRUE(v_str.isString());    EXPECT_EQ(before, v_str.getString());}